1	package middleware
2	
3	import (
4		"crypto/sha256"
5		"database/sql"
6		"encoding/hex"
7		"errors"
8		"time"
9	
10		"github.com/gofiber/fiber/v2"
11	
12		"w2t86/internal/models"
13		"w2t86/internal/repository"
14	)
15	
16	// AuthMiddleware validates session cookies and loads the current user into
17	// request locals.
18	type AuthMiddleware struct {
19		sessionRepo *repository.SessionRepository
20		userRepo    *repository.UserRepository
21	}
22	
23	// NewAuthMiddleware creates an AuthMiddleware from the provided repositories.
24	func NewAuthMiddleware(sr *repository.SessionRepository, ur *repository.UserRepository) *AuthMiddleware {
25		return &AuthMiddleware{sessionRepo: sr, userRepo: ur}
26	}
27	
28	// RequireAuth is a Fiber middleware handler that:
29	//  1. Reads the "session_token" cookie.
30	//  2. Hashes it with SHA-256.
31	//  3. Looks up the session in the database.
32	//  4. Verifies the session has not expired.
33	//  5. Loads the associated user and stores it in c.Locals("user").
34	//
35	// Returns 401 JSON {"error": "unauthorized"} on any failure.
36	func (m *AuthMiddleware) RequireAuth() fiber.Handler {
37		return func(c *fiber.Ctx) error {
38			token := c.Cookies("session_token")
39			if token == "" {
40				return c.Status(fiber.StatusUnauthorized).JSON(fiber.Map{"error": "unauthorized"})
41			}
42	
43			// Hash the raw token the same way it was stored on login.
44			hash := hashToken(token)
45	
46			session, err := m.sessionRepo.GetByTokenHash(hash)
47			if err != nil {
48				if errors.Is(err, sql.ErrNoRows) {
49					return c.Status(fiber.StatusUnauthorized).JSON(fiber.Map{"error": "unauthorized"})
50				}
51				return c.Status(fiber.StatusUnauthorized).JSON(fiber.Map{"error": "unauthorized"})
52			}
53	
54			// Parse expires_at stored as RFC3339 text.
55			expiresAt, err := time.Parse(time.RFC3339, session.ExpiresAt)
56			if err != nil {
57				return c.Status(fiber.StatusUnauthorized).JSON(fiber.Map{"error": "unauthorized"})
58			}
59			if time.Now().UTC().After(expiresAt) {
60				return c.Status(fiber.StatusUnauthorized).JSON(fiber.Map{"error": "unauthorized"})
61			}
62	
63			user, err := m.userRepo.GetByID(session.UserID)
64			if err != nil {
65				if errors.Is(err, sql.ErrNoRows) {
66					return c.Status(fiber.StatusUnauthorized).JSON(fiber.Map{"error": "unauthorized"})
67				}
68				return c.Status(fiber.StatusUnauthorized).JSON(fiber.Map{"error": "unauthorized"})
69			}
70	
71			c.Locals("user", user)
72			return c.Next()
73		}
74	}
75	
76	// GetUser extracts the authenticated *models.User from fiber.Ctx locals.
77	// Returns nil when called outside of a RequireAuth-protected route.
78	func GetUser(c *fiber.Ctx) *models.User {
79		u, _ := c.Locals("user").(*models.User)
80		return u
81	}
82	
83	// hashToken returns the lowercase hex SHA-256 digest of token.
84	func hashToken(token string) string {
85		sum := sha256.Sum256([]byte(token))
86		return hex.EncodeToString(sum[:])
87	}
