262	// ---------------------------------------------------------------
263	// State machine transition
264	// ---------------------------------------------------------------
265	
266	// validTransitions maps (fromStatus, toStatus) pairs that are permitted.
267	var validTransitions = map[string]map[string]bool{
268		"pending_payment": {
269			"pending_shipment": true,
270			"canceled":         true,
271		},
272		"pending_shipment": {
273			"in_transit": true,
274			"canceled":   true,
275		},
276		"in_transit": {
277			"completed": true,
278			"canceled":  true,
279		},
280	}
281	
282	// Transition validates and applies an order status transition within a
283	// transaction. It also:
284	//   - Updates auto_close_at: pending_shipment → now+72h, all others → NULL.
285	//   - On cancel: rolls back inventory (available_qty += qty, reserved_qty -= qty).
286	//   - On completed: decrements reserved_qty (items are physically fulfilled).
287	//   - Inserts an order_event row.
288	func (r *OrderRepository) Transition(orderID, actorID int64, toStatus, note string, materialRepo *MaterialRepository) error {
289		tx, err := r.db.Begin()
290		if err != nil {
291			return fmt.Errorf("repository: Transition: begin tx: %w", err)
292		}
293		defer tx.Rollback() //nolint:errcheck
294	
295		// Load current status.
296		var fromStatus string
297		if err := tx.QueryRow(`SELECT status FROM orders WHERE id = ?`, orderID).Scan(&fromStatus); err != nil {
298			if errors.Is(err, sql.ErrNoRows) {
299				return fmt.Errorf("repository: Transition: order %d not found", orderID)
300			}
301			return fmt.Errorf("repository: Transition: load status: %w", err)
302		}
303	
304		// Validate transition.
305		allowed, ok := validTransitions[fromStatus]
306		if !ok || !allowed[toStatus] {
307			return fmt.Errorf("repository: Transition: invalid transition %q → %q", fromStatus, toStatus)
308		}
309	
310		// Determine new auto_close_at value.
311		var autoCloseExpr string
312		switch toStatus {
313		case "pending_shipment":
314			autoCloseExpr = "datetime('now', '+72 hours')"
315		default:
316			autoCloseExpr = "NULL"
317		}
318	
319		updateOrderQ := fmt.Sprintf(`
320			UPDATE orders
321			SET    status       = ?,
322			       auto_close_at = %s,
323			       updated_at   = datetime('now')
324			WHERE  id = ?`, autoCloseExpr)
325	
326		if _, err := tx.Exec(updateOrderQ, toStatus, orderID); err != nil {
327			return fmt.Errorf("repository: Transition: update order: %w", err)
328		}
329	
330		// Handle inventory side effects.
331		if toStatus == "canceled" {
332			// Roll back reserved inventory for every item.
333			const itemsQ = `SELECT material_id, qty FROM order_items WHERE order_id = ?`
334			rows, err := tx.Query(itemsQ, orderID)
335			if err != nil {
336				return fmt.Errorf("repository: Transition: query items for rollback: %w", err)
337			}
338			type itemRef struct {
339				materialID int64
340				qty        int
341			}
342			var items []itemRef
343			for rows.Next() {
344				var it itemRef
345				if err := rows.Scan(&it.materialID, &it.qty); err != nil {
346					rows.Close()
347					return err
348				}
349				items = append(items, it)
350			}
351			rows.Close()
352			if err := rows.Err(); err != nil {
353				return err
354			}
355	
356			const rollbackQ = `
357				UPDATE materials
358				SET    available_qty = available_qty + ?,
359				       reserved_qty  = CASE WHEN reserved_qty - ? < 0 THEN 0 ELSE reserved_qty - ? END,
360				       updated_at    = datetime('now')
361				WHERE  id = ?`
362			for _, it := range items {
363				if _, err := tx.Exec(rollbackQ, it.qty, it.qty, it.qty, it.materialID); err != nil {
364					return fmt.Errorf("repository: Transition: rollback inventory material %d: %w", it.materialID, err)
365				}
366			}
367		} else if toStatus == "completed" {
368			// Decrement reserved_qty — items are physically handed over.
369			const itemsQ = `SELECT material_id, qty FROM order_items WHERE order_id = ?`
370			rows, err := tx.Query(itemsQ, orderID)
371			if err != nil {
372				return fmt.Errorf("repository: Transition: query items for fulfillment: %w", err)
373			}
374			type itemRef struct {
375				materialID int64
376				qty        int
377			}
378			var items []itemRef
379			for rows.Next() {
380				var it itemRef
381				if err := rows.Scan(&it.materialID, &it.qty); err != nil {
382					rows.Close()
383					return err
384				}
385				items = append(items, it)
386			}
387			rows.Close()
388			if err := rows.Err(); err != nil {
389				return err
390			}
391	
392			const fulfillQ = `
393				UPDATE materials
394				SET    reserved_qty = CASE WHEN reserved_qty - ? < 0 THEN 0 ELSE reserved_qty - ? END,
395				       updated_at   = datetime('now')
396				WHERE  id = ?`
397			for _, it := range items {
398				if _, err := tx.Exec(fulfillQ, it.qty, it.qty, it.materialID); err != nil {
399					return fmt.Errorf("repository: Transition: fulfill inventory material %d: %w", it.materialID, err)
