12	
13	// IssueItem identifies a single material line to be physically issued.
14	// IssuedQty is the number of copies the clerk is handing out right now; it may
15	// be less than the full ordered quantity, in which case a backorder is created
16	// for the remainder.  When IssuedQty is 0 it defaults to the full ordered qty.
17	type IssueItem struct {
18		MaterialID int64
19		Qty        int // total ordered quantity
20		IssuedQty  int // quantity being issued in this operation (0 = full qty)
21	}
22	
23	// DistributionService orchestrates all clerk-facing distribution operations:
24	// issuing, returning, exchanging, and reissuing physical copies.
25	type DistributionService struct {
26		distRepo     *repository.DistributionRepository
27		orderRepo    *repository.OrderRepository
28		materialRepo *repository.MaterialRepository
29	}
30	
31	// NewDistributionService wires the service to its three repositories.
32	func NewDistributionService(
33		dr *repository.DistributionRepository,
34		or *repository.OrderRepository,
35		mr *repository.MaterialRepository,
36	) *DistributionService {
37		return &DistributionService{
38			distRepo:     dr,
39			orderRepo:    or,
40			materialRepo: mr,
41		}
42	}
43	
44	// ---------------------------------------------------------------
45	// Issue
46	// ---------------------------------------------------------------
47	
48	// IssueItems records an "issued" distribution event for every item in the
49	// slice, marks the corresponding order_items as fulfilled, and — when all
50	// items for the order are fulfilled — advances the order status to in_transit.
51	//
52	// scanID is a barcode / copy identifier that binds the physical copy to the
53	// event.  It is shared across all items in a single issue batch.
54	func (s *DistributionService) IssueItems(orderID, actorID int64, scanID string, items []IssueItem) error {
55		if len(items) == 0 {
56			return errors.New("service: IssueItems: at least one item required")
57		}
58	
59		order, err := s.orderRepo.GetByID(orderID)
60		if err != nil {
61			if errors.Is(err, sql.ErrNoRows) {
62				return fmt.Errorf("service: IssueItems: order %d not found", orderID)
63			}
64			return fmt.Errorf("service: IssueItems: load order: %w", err)
65		}
66		if order.Status != "pending_shipment" && order.Status != "in_transit" {
67			return fmt.Errorf("service: IssueItems: order %d is not ready to issue (status=%s)", orderID, order.Status)
68		}
69	
70		scanIDPtr := &scanID
71		actorIDPtr := &actorID
72		orderIDPtr := &orderID
73	
74		// Load the authoritative order line items and build a lookup map.
75		orderItems, err := s.orderRepo.GetItemsByOrderID(orderID)
76		if err != nil {
77			return fmt.Errorf("service: IssueItems: load order items: %w", err)
78		}
79		orderedQty := make(map[int64]int, len(orderItems))
80		for _, oi := range orderItems {
81			orderedQty[oi.MaterialID] = oi.Qty
82		}
83	
84		for _, item := range items {
85			// Reject materials that are not part of this order.
86			oqty, ok := orderedQty[item.MaterialID]
87			if !ok {
88				return fmt.Errorf("service: IssueItems: material %d is not part of order %d", item.MaterialID, orderID)
89			}
90	
91			issued := item.IssuedQty
92			if issued <= 0 {
93				issued = item.Qty
94			}
95			if issued <= 0 {
96				return fmt.Errorf("service: IssueItems: qty must be positive for material %d", item.MaterialID)
97			}
98			// Issued quantity must not exceed the DB-authoritative ordered quantity.
99			if issued > oqty {
100				return fmt.Errorf("service: IssueItems: issued qty (%d) exceeds ordered qty (%d) for material %d",
101					issued, oqty, item.MaterialID)
102			}
103	
104			evt := &models.DistributionEvent{
105				OrderID:     orderIDPtr,
106				MaterialID:  item.MaterialID,
107				Qty:         issued, // record only the quantity actually handed out
108				EventType:   "issued",
109				ScanID:      scanIDPtr,
110				ActorID:     actorIDPtr,
111				CustodyFrom: stringPtr("clerk"),
112				CustodyTo:   stringPtr("student"),
113			}
114			if _, err := s.distRepo.RecordEvent(evt); err != nil {
115				return fmt.Errorf("service: IssueItems: record event for material %d: %w", item.MaterialID, err)
116			}
117		}
118	
119		// Mark order items as fulfilled and potentially advance order status.
120		if err := s.markItemsFulfilled(orderID, actorID, items); err != nil {
121			return fmt.Errorf("service: IssueItems: mark fulfilled: %w", err)
122		}
123	
124		for _, item := range items {
125			observability.Distribution.Info("item issued", "order_id", orderID, "material_id", item.MaterialID, "qty", item.Qty, "scan_id", scanID, "actor_id", actorID)
126		}
127		return nil
128	}
129	
130	// markItemsFulfilled updates fulfillment_status for each issued item.
131	// When the issued quantity equals the ordered quantity the item is marked
132	// "fulfilled"; when it is less, the item is marked "backordered" and a
133	// backorder record is created for the shortfall.
134	// The order is advanced from pending_shipment → in_transit on the first issue.
135	func (s *DistributionService) markItemsFulfilled(orderID, actorID int64, items []IssueItem) error {
136		for _, item := range items {
137			issued := item.IssuedQty
138			if issued <= 0 {
139				issued = item.Qty
140			}
141	
142			if issued >= item.Qty {
143				// Fully satisfied — mark fulfilled.
144				if err := s.orderRepo.MarkOrderItemFulfilled(orderID, item.MaterialID); err != nil {
145					return fmt.Errorf("markItemsFulfilled: mark fulfilled material %d: %w", item.MaterialID, err)
146				}
147			} else {
148				// Partial issue — mark backordered and record the shortfall.
149				if err := s.orderRepo.MarkOrderItemBackordered(orderID, item.MaterialID); err != nil {
150					return fmt.Errorf("markItemsFulfilled: mark backordered material %d: %w", item.MaterialID, err)
151				}
152				itemID, err := s.orderRepo.GetOrderItemID(orderID, item.MaterialID)
153				if err != nil {
154					return fmt.Errorf("markItemsFulfilled: get order_item_id material %d: %w", item.MaterialID, err)
155				}
156				shortfall := item.Qty - issued
157				if _, err := s.orderRepo.CreateBackorder(itemID, shortfall); err != nil {
158					return fmt.Errorf("markItemsFulfilled: create backorder material %d: %w", item.MaterialID, err)
159				}
160				observability.Distribution.Warn("partial issue — backorder created",
161					"order_id", orderID, "material_id", item.MaterialID,
162					"issued", issued, "shortfall", shortfall)
163			}
164		}
165	
166		// Advance order from pending_shipment → in_transit on first issue.
167		order, err := s.orderRepo.GetByID(orderID)
168		if err != nil {
169			return err
170		}
171		if order.Status == "pending_shipment" {
172			if err := s.orderRepo.Transition(orderID, actorID, "in_transit", "items issued by clerk", s.materialRepo); err != nil {
173				return fmt.Errorf("markItemsFulfilled: advance to in_transit: %w", err)
174			}
175		}
176	
177		return nil
178	}
179	
180	// ---------------------------------------------------------------
181	// Return
182	// ---------------------------------------------------------------
183	
184	// RecordReturn records a "returned" distribution event and releases inventory
185	// (increments available_qty by qty).
186	//
187	// returnRequestID must reference an approved return_request of type "return"
188	// for orderID. The call is rejected if the request does not exist, is not yet
189	// approved, or belongs to a different order.
190	func (s *DistributionService) RecordReturn(orderID, materialID, actorID, returnRequestID int64, scanID string, qty int) error {
191		if qty <= 0 {
192			return errors.New("service: RecordReturn: qty must be positive")
193		}
194	
195		// Require an approved return request of the correct type.
196		rr, err := s.orderRepo.GetReturnRequestByID(returnRequestID)
197		if err != nil {
198			return fmt.Errorf("service: RecordReturn: load return request: %w", err)
199		}
200		if rr.Status != "approved" {
201			return fmt.Errorf("service: RecordReturn: return request %d is not approved (status=%s)", returnRequestID, rr.Status)
202		}
203		if rr.OrderID != orderID {
204			return fmt.Errorf("service: RecordReturn: return request %d belongs to order %d, not %d", returnRequestID, rr.OrderID, orderID)
205		}
206		if rr.Type != "return" {
207			return fmt.Errorf("service: RecordReturn: return request %d has wrong type %q (expected 'return')", returnRequestID, rr.Type)
208		}
209	
210		// Verify order exists.
211		if _, err := s.orderRepo.GetByID(orderID); err != nil {
212			if errors.Is(err, sql.ErrNoRows) {
213				return fmt.Errorf("service: RecordReturn: order %d not found", orderID)
214			}
215			return fmt.Errorf("service: RecordReturn: load order: %w", err)
216		}
217	
218		orderIDPtr := &orderID
219		actorIDPtr := &actorID
220		scanIDPtr := &scanID
221	
222		evt := &models.DistributionEvent{
223			OrderID:     orderIDPtr,
224			MaterialID:  materialID,
225			Qty:         qty,
226			EventType:   "returned",
227			ScanID:      scanIDPtr,
228			ActorID:     actorIDPtr,
229			CustodyFrom: stringPtr("student"),
230			CustodyTo:   stringPtr("clerk"),
231		}
232		if _, err := s.distRepo.RecordEvent(evt); err != nil {
233			return fmt.Errorf("service: RecordReturn: record event: %w", err)
234		}
235	
236		// Release inventory back to available stock.
237		if err := s.materialRepo.Release(materialID, qty); err != nil {
238			return fmt.Errorf("service: RecordReturn: release inventory: %w", err)
239		}
240	
241		observability.Distribution.Info("item returned", "order_id", orderID, "material_id", materialID, "qty", qty, "scan_id", scanID, "actor_id", actorID)
242		return nil
243	}
244	
245	// ---------------------------------------------------------------
246	// Exchange
247	// ---------------------------------------------------------------
248	
249	// RecordExchange swaps an old copy for a new one in a single logical operation:
250	//  1. Validates the approved exchange request.
251	//  2. Records a "returned" event for oldMaterialID.
252	//  3. Verifies the new material has available stock.
253	//  4. Records an "issued" event for newMaterialID and decrements its
254	//     available_qty.
255	//
256	// returnRequestID must reference an approved return_request of type "exchange"
257	// for orderID.
258	func (s *DistributionService) RecordExchange(orderID, oldMaterialID, newMaterialID, actorID, returnRequestID int64, scanID string, qty int) error {
259		if qty <= 0 {
260			return errors.New("service: RecordExchange: qty must be positive")
261		}
262	
263		// Require an approved exchange request of the correct type.
264		rr, err := s.orderRepo.GetReturnRequestByID(returnRequestID)
265		if err != nil {
266			return fmt.Errorf("service: RecordExchange: load return request: %w", err)
267		}
268		if rr.Status != "approved" {
269			return fmt.Errorf("service: RecordExchange: return request %d is not approved (status=%s)", returnRequestID, rr.Status)
270		}
271		if rr.OrderID != orderID {
272			return fmt.Errorf("service: RecordExchange: return request %d belongs to order %d, not %d", returnRequestID, rr.OrderID, orderID)
273		}
274		if rr.Type != "exchange" {
275			return fmt.Errorf("service: RecordExchange: return request %d has wrong type %q (expected 'exchange')", returnRequestID, rr.Type)
276		}
277	
278		// Return the old copy (releases its inventory).
279		// We pass 0 as returnRequestID to the inner RecordReturn because the
280		// exchange request already covers both legs; RecordReturn's own request
281		// check is bypassed here via the internal call path.
282		if err := s.recordReturnInternal(orderID, oldMaterialID, actorID, scanID, qty); err != nil {
283			return fmt.Errorf("service: RecordExchange: return old: %w", err)
284		}
285	
286		// Check new material stock.
287		newMat, err := s.materialRepo.GetByID(newMaterialID)
288		if err != nil {
289			if errors.Is(err, sql.ErrNoRows) {
290				return fmt.Errorf("service: RecordExchange: new material %d not found", newMaterialID)
291			}
292			return fmt.Errorf("service: RecordExchange: load new material: %w", err)
293		}
294		if newMat.AvailableQty < qty {
295			return fmt.Errorf("service: RecordExchange: insufficient stock for material %q (available %d, requested %d)",
296				newMat.Title, newMat.AvailableQty, qty)
297		}
298	
299		orderIDPtr := &orderID
300		actorIDPtr := &actorID
301		newScanID := scanID + "_exch"
302		scanIDPtr := &newScanID
303	
304		evt := &models.DistributionEvent{
305			OrderID:     orderIDPtr,
306			MaterialID:  newMaterialID,
307			Qty:         qty,
308			EventType:   "issued",
309			ScanID:      scanIDPtr,
310			ActorID:     actorIDPtr,
311			CustodyFrom: stringPtr("clerk"),
312			CustodyTo:   stringPtr("student"),
313		}
314		if _, err := s.distRepo.RecordEvent(evt); err != nil {
315			return fmt.Errorf("service: RecordExchange: record issue event: %w", err)
316		}
317	
318		// Reserve the newly issued material's inventory.
319		if err := s.materialRepo.Reserve(newMaterialID, qty); err != nil {
320			return fmt.Errorf("service: RecordExchange: reserve new material inventory: %w", err)
321		}
322	
323		observability.Distribution.Info("item exchanged", "order_id", orderID, "old_material_id", oldMaterialID, "new_material_id", newMaterialID, "qty", qty, "actor_id", actorID)
324		return nil
325	}
326	
327	
328	// ---------------------------------------------------------------
329	// Reissue
330	// ---------------------------------------------------------------
331	
332	// ReissueItem handles lost or damaged copy replacement:
333	//   - Records a "lost" or "damaged" event for oldScanID (marking it out of
334	//     circulation).
335	//   - Records a new "issued" event for newScanID.
336	//
337	// reason must be "lost" or "damaged".
338	func (s *DistributionService) ReissueItem(orderID, materialID, actorID int64, oldScanID, newScanID, reason string) error {
339		if reason != "lost" && reason != "damaged" {
340			return fmt.Errorf("service: ReissueItem: invalid reason %q (must be 'lost' or 'damaged')", reason)
341		}
342		if oldScanID == "" || newScanID == "" {
343			return errors.New("service: ReissueItem: both oldScanID and newScanID are required")
344		}
345	
346		// Verify order exists.
347		if _, err := s.orderRepo.GetByID(orderID); err != nil {
348			if errors.Is(err, sql.ErrNoRows) {
349				return fmt.Errorf("service: ReissueItem: order %d not found", orderID)
350			}
351			return fmt.Errorf("service: ReissueItem: load order: %w", err)
352		}
353	
354		orderIDPtr := &orderID
355		actorIDPtr := &actorID
356	
357		// Record the loss/damage event for the old scan ID.
358		oldEvt := &models.DistributionEvent{
359			OrderID:    orderIDPtr,
360			MaterialID: materialID,
361			Qty:        1,
362			EventType:  reason, // "lost" or "damaged"
363			ScanID:     &oldScanID,
364			ActorID:    actorIDPtr,
365		}
366		if _, err := s.distRepo.RecordEvent(oldEvt); err != nil {
367			return fmt.Errorf("service: ReissueItem: record %s event: %w", reason, err)
368		}
369	
370		// Issue the replacement copy.
371		newEvt := &models.DistributionEvent{
372			OrderID:     orderIDPtr,
373			MaterialID:  materialID,
374			Qty:         1,
375			EventType:   "issued",
376			ScanID:      &newScanID,
377			ActorID:     actorIDPtr,
378			CustodyFrom: stringPtr("clerk"),
379			CustodyTo:   stringPtr("student"),
380		}
381		if _, err := s.distRepo.RecordEvent(newEvt); err != nil {
382			return fmt.Errorf("service: ReissueItem: record replacement issue event: %w", err)
383		}
384	
385		observability.Distribution.Info("item reissued", "old_scan_id", oldScanID, "new_scan_id", newScanID, "reason", reason)
386		return nil
387	}
388	
389	// ---------------------------------------------------------------
390	// Ledger / chain queries — thin pass-through
391	// ---------------------------------------------------------------
392	
393	// GetLedger returns a paginated, filtered view of distribution events.
394	func (s *DistributionService) GetLedger(filters repository.DistributionFilter, limit, offset int) ([]models.DistributionEvent, error) {
395		return s.distRepo.ListEvents(filters, limit, offset)
396	}
397	
398	// GetCustodyChain returns the full event history for a physical copy.
399	func (s *DistributionService) GetCustodyChain(scanID string) ([]models.DistributionEvent, error) {
400		if scanID == "" {
401			return nil, errors.New("service: GetCustodyChain: scanID is required")
402		}
403		return s.distRepo.GetCustodyChain(scanID)
404	}
405	
406	// GetPendingIssues returns the clerk's pick list.
407	func (s *DistributionService) GetPendingIssues(limit, offset int) ([]repository.PendingIssue, error) {
408		return s.distRepo.GetPendingIssues(limit, offset)
409	}
410	
411	// CountBackorders returns the total number of unresolved backorder records.
412	func (s *DistributionService) CountBackorders() (int, error) {
413		return s.distRepo.CountBackorders()
414	}
415	
416	// ---------------------------------------------------------------
417	// helpers
418	// ---------------------------------------------------------------
419	
420	// recordReturnInternal records the return event and releases inventory without
421	// validating a return_request. It is used internally by RecordExchange, which
422	// has already validated the exchange request before splitting into legs.
423	func (s *DistributionService) recordReturnInternal(orderID, materialID, actorID int64, scanID string, qty int) error {
424		orderIDPtr := &orderID
425		actorIDPtr := &actorID
426		scanIDPtr := &scanID
427	
428		evt := &models.DistributionEvent{
429			OrderID:     orderIDPtr,
430			MaterialID:  materialID,
431			Qty:         qty,
432			EventType:   "returned",
433			ScanID:      scanIDPtr,
434			ActorID:     actorIDPtr,
435			CustodyFrom: stringPtr("student"),
436			CustodyTo:   stringPtr("clerk"),
437		}
438		if _, err := s.distRepo.RecordEvent(evt); err != nil {
439			return fmt.Errorf("record event: %w", err)
440		}
441		if err := s.materialRepo.Release(materialID, qty); err != nil {
442			return fmt.Errorf("release inventory: %w", err)
443		}
444		return nil
445	}
