1	package services
2	
3	import (
4		"crypto/rand"
5		"crypto/sha256"
6		"database/sql"
7		"encoding/hex"
8		"errors"
9		"fmt"
10		"time"
11	
12		"w2t86/internal/config"
13		"w2t86/internal/crypto"
14		"w2t86/internal/models"
15		"w2t86/internal/observability"
16		"w2t86/internal/repository"
17	)
18	
19	const (
20		maxFailedAttempts = 5
21		lockDuration      = 15 * time.Minute
22		sessionDuration   = 24 * time.Hour
23		minPasswordLen    = 12
24	)
25	
26	// AuthService handles user registration, login, and logout.
27	type AuthService struct {
28		userRepo    *repository.UserRepository
29		sessionRepo *repository.SessionRepository
30		cfg         *config.Config
31	}
32	
33	// NewAuthService creates an AuthService with the provided dependencies.
34	func NewAuthService(
35		ur *repository.UserRepository,
36		sr *repository.SessionRepository,
37		cfg *config.Config,
38	) *AuthService {
39		return &AuthService{userRepo: ur, sessionRepo: sr, cfg: cfg}
40	}
41	
42	// Login authenticates a user by username and password.
43	//
44	// Rules:
45	//   - Account must exist and not be soft-deleted.
46	//   - If locked_until is in the future, return error "account locked".
47	//   - On password mismatch, increment failed_attempts.
48	//     On the 5th failure, lock for 15 minutes and return "account locked".
49	//   - On success, reset failed attempts, create a 24-hour session, and return
50	//     the raw 32-byte hex token.
51	func (s *AuthService) Login(username, password string) (token string, user *models.User, err error) {
52		user, err = s.userRepo.GetByUsername(username)
53		if err != nil {
54			if errors.Is(err, sql.ErrNoRows) {
55				return "", nil, errors.New("invalid username or password")
56			}
57			return "", nil, fmt.Errorf("auth: login: %w", err)
58		}
59	
60		// Check if the account is currently locked.
61		if user.LockedUntil != nil {
62			until, parseErr := time.Parse(time.RFC3339, *user.LockedUntil)
63			if parseErr == nil && time.Now().UTC().Before(until) {
64				observability.Security.Warn("login attempt on locked account", "username", username)
65				return "", nil, errors.New("account locked")
66			}
67		}
68	
69		// Verify password.
70		if !crypto.CheckPassword(user.PasswordHash, password) {
71			observability.Auth.Warn("login failed", "username", username, "reason", "wrong_password")
72			observability.M.LoginFailures.Add(1)
73	
74			// Increment counter first so we can check the new value.
75			if incErr := s.userRepo.IncrementFailedAttempts(user.ID); incErr != nil {
76				return "", nil, fmt.Errorf("auth: login: increment attempts: %w", incErr)
77			}
78	
79			newAttempts := user.FailedAttempts + 1
80			if newAttempts >= maxFailedAttempts {
81				lockUntil := time.Now().UTC().Add(lockDuration)
82				if lockErr := s.userRepo.LockUntil(user.ID, lockUntil); lockErr != nil {
83					return "", nil, fmt.Errorf("auth: login: lock account: %w", lockErr)
84				}
85				observability.Security.Warn("account locked", "username", username, "user_id", user.ID)
86				return "", nil, errors.New("account locked")
87			}
88	
89			return "", nil, errors.New("invalid username or password")
90		}
91	
92		// Password matched — reset failure tracking.
93		if resetErr := s.userRepo.ResetFailedAttempts(user.ID); resetErr != nil {
94			return "", nil, fmt.Errorf("auth: login: reset attempts: %w", resetErr)
95		}
96	
97		// Generate a 32-byte random token encoded as lowercase hex (64 chars).
98		rawToken, err := generateToken()
99		if err != nil {
100			return "", nil, fmt.Errorf("auth: login: generate token: %w", err)
101		}
102	
103		tokenHash := hashToken(rawToken)
104		expiresAt := time.Now().UTC().Add(sessionDuration)
105	
106		if _, err = s.sessionRepo.Create(user.ID, tokenHash, expiresAt); err != nil {
107			return "", nil, fmt.Errorf("auth: login: create session: %w", err)
108		}
109	
110		// Reload user so caller sees the fresh state.
111		user, err = s.userRepo.GetByID(user.ID)
112		if err != nil {
113			return "", nil, fmt.Errorf("auth: login: reload user: %w", err)
114		}
115	
116		observability.Auth.Info("login success", "username", username, "user_id", user.ID)
117		observability.M.LoginSuccess.Add(1)
118	
119		return rawToken, user, nil
120	}
121	
122	// Logout invalidates the session identified by the raw token.
123	func (s *AuthService) Logout(token string) error {
124		hash := hashToken(token)
125		if err := s.sessionRepo.Delete(hash); err != nil {
126			return fmt.Errorf("auth: logout: %w", err)
127		}
128		observability.Auth.Info("logout", "token_hash_prefix", hash[:8])
129		return nil
130	}
131	
132	// ChangePassword hashes newPassword and updates the user's password_hash.
133	// It also clears the must_change_password flag so the user is not redirected again.
134	func (s *AuthService) ChangePassword(userID int64, newPassword string) error {
135		if len(newPassword) < minPasswordLen {
136			return fmt.Errorf("auth: ChangePassword: password must be at least %d characters", minPasswordLen)
137		}
138		hash, err := crypto.HashPassword(newPassword)
139		if err != nil {
140			return fmt.Errorf("auth: ChangePassword: %w", err)
141		}
142		if err := s.userRepo.Update(userID, map[string]interface{}{"password_hash": hash}); err != nil {
143			return fmt.Errorf("auth: ChangePassword: %w", err)
144		}
145		if err := s.userRepo.ClearMustChangePassword(userID); err != nil {
146			return fmt.Errorf("auth: ChangePassword: clear flag: %w", err)
147		}
148		observability.Security.Info("password changed", "user_id", userID)
149		return nil
150	}
151	
152	// Register validates inputs, hashes the password, and creates a new user.
153	// Password must be at least 12 characters long.
154	func (s *AuthService) Register(username, email, password, role string) (*models.User, error) {
155		if len(password) < minPasswordLen {
156			return nil, fmt.Errorf("auth: register: password must be at least %d characters", minPasswordLen)
157		}
158	
159		hash, err := crypto.HashPassword(password)
160		if err != nil {
161			return nil, fmt.Errorf("auth: register: %w", err)
162		}
163	
164		user, err := s.userRepo.Create(username, email, hash, role)
165		if err != nil {
166			return nil, fmt.Errorf("auth: register: %w", err)
167		}
168	
169		observability.Auth.Info("user registered", "username", username, "role", role)
170		return user, nil
171	}
172	
173	// ---------------------------------------------------------------
174	// helpers
175	// ---------------------------------------------------------------
176	
177	// generateToken returns a cryptographically-random 32-byte value encoded as
178	// a 64-character lowercase hex string.
179	func generateToken() (string, error) {
180		b := make([]byte, 32)
181		if _, err := rand.Read(b); err != nil {
182			return "", err
183		}
184		return hex.EncodeToString(b), nil
185	}
186	
187	// hashToken returns the SHA-256 hex digest of token.
188	func hashToken(token string) string {
189		sum := sha256.Sum256([]byte(token))
190		return hex.EncodeToString(sum[:])
191	}
