13	// OrderService orchestrates all order-lifecycle, return, and inventory operations.
14	type OrderService struct {
15		orderRepo    *repository.OrderRepository
16		materialRepo *repository.MaterialRepository
17	}
18	
19	// NewOrderService creates an OrderService wired to the given repositories.
20	func NewOrderService(or *repository.OrderRepository, mr *repository.MaterialRepository) *OrderService {
21		return &OrderService{orderRepo: or, materialRepo: mr}
22	}
23	
24	// ---------------------------------------------------------------
25	// Order placement
26	// ---------------------------------------------------------------
27	
28	// PlaceOrder validates that every requested material exists and has sufficient
29	// stock, then delegates to OrderRepository.Create.
30	func (s *OrderService) PlaceOrder(userID int64, items []repository.OrderItemInput) (*models.Order, error) {
31		if len(items) == 0 {
32			return nil, errors.New("service: PlaceOrder: cart is empty")
33		}
34	
35		for _, it := range items {
36			if it.Qty <= 0 {
37				return nil, fmt.Errorf("service: PlaceOrder: quantity must be positive for material %d", it.MaterialID)
38			}
39			mat, err := s.materialRepo.GetByID(it.MaterialID)
40			if err != nil {
41				if errors.Is(err, sql.ErrNoRows) {
42					return nil, fmt.Errorf("service: PlaceOrder: material %d not found", it.MaterialID)
43				}
44				return nil, fmt.Errorf("service: PlaceOrder: fetch material %d: %w", it.MaterialID, err)
45			}
46			if mat.Status != "active" {
47				return nil, fmt.Errorf("service: PlaceOrder: material %q is not available for ordering", mat.Title)
48			}
49			if mat.AvailableQty < it.Qty {
50				return nil, fmt.Errorf("service: PlaceOrder: insufficient stock for %q (available: %d, requested: %d)",
51					mat.Title, mat.AvailableQty, it.Qty)
52			}
53		}
54	
55		order, err := s.orderRepo.Create(userID, items)
56		if err != nil {
57			return nil, fmt.Errorf("service: PlaceOrder: %w", err)
58		}
59	
60		observability.Orders.Info("order placed", "order_id", order.ID, "user_id", userID, "item_count", len(items), "total_amount", order.TotalAmount)
61		observability.M.OrdersCreated.Add(1)
62	
63		return order, nil
64	}
65	
66	// ---------------------------------------------------------------
67	// Student actions
68	// ---------------------------------------------------------------
69	
70	// ConfirmPayment transitions an order from pending_payment → pending_shipment.
71	// Only the order owner may confirm payment.
72	func (s *OrderService) ConfirmPayment(orderID, userID int64) error {
73		order, err := s.orderRepo.GetByID(orderID)
74		if err != nil {
75			return fmt.Errorf("service: ConfirmPayment: %w", err)
76		}
77		if order.UserID != userID {
78			return errors.New("service: ConfirmPayment: not authorized")
79		}
80		if order.Status != "pending_payment" {
81			return fmt.Errorf("service: ConfirmPayment: order is %q, expected pending_payment", order.Status)
82		}
83		if err := s.orderRepo.Transition(orderID, userID, "pending_shipment", "payment confirmed", s.materialRepo); err != nil {
84			return err
85		}
86		observability.Orders.Info("payment confirmed", "order_id", orderID, "user_id", userID)
87		return nil
88	}
89	
90	// CancelOrder cancels an order. Business rules:
91	//   - Students can only cancel their own orders when in pending_payment.
92	//   - Clerks cannot cancel orders.
93	//   - Admins/instructors can cancel pending_payment or pending_shipment orders.
94	//   - Only admins can cancel in_transit orders.
95	func (s *OrderService) CancelOrder(orderID, actorID int64, role string) error {
96		order, err := s.orderRepo.GetByID(orderID)
97		if err != nil {
98			return fmt.Errorf("service: CancelOrder: %w", err)
99		}
100	
101		switch role {
102		case "student":
103			if order.UserID != actorID {
104				return errors.New("service: CancelOrder: not authorized")
105			}
106			if order.Status != "pending_payment" {
107				return fmt.Errorf("service: CancelOrder: students may only cancel orders in pending_payment (current: %q)", order.Status)
108			}
109		case "admin", "instructor":
110			if order.Status == "in_transit" && role != "admin" {
111				return errors.New("service: CancelOrder: only admins can cancel in-transit orders")
112			}
113			if order.Status == "completed" {
114				return errors.New("service: CancelOrder: completed orders cannot be canceled")
115			}
116			if order.Status == "canceled" {
117				return errors.New("service: CancelOrder: order is already canceled")
118			}
119		case "clerk":
120			return errors.New("service: CancelOrder: clerks are not permitted to cancel orders")
121		default:
122			return errors.New("service: CancelOrder: unknown role")
123		}
124	
125		note := fmt.Sprintf("canceled by %s (id=%d)", role, actorID)
126		if err := s.orderRepo.Transition(orderID, actorID, "canceled", note, s.materialRepo); err != nil {
127			return err
128		}
129		observability.Orders.Info("order canceled", "order_id", orderID, "actor_id", actorID, "role", role, "reason", "user_requested")
130		observability.M.OrdersCanceled.Add(1)
131		return nil
132	}
133	
134	// ---------------------------------------------------------------
135	// Clerk actions
136	// ---------------------------------------------------------------
137	
138	// MarkShipped transitions an order from pending_shipment → in_transit.
139	// Only clerks (or admins) may call this.
140	func (s *OrderService) MarkShipped(orderID, actorID int64) error {
141		order, err := s.orderRepo.GetByID(orderID)
142		if err != nil {
143			return fmt.Errorf("service: MarkShipped: %w", err)
144		}
145		if order.Status != "pending_shipment" {
146			return fmt.Errorf("service: MarkShipped: order is %q, expected pending_shipment", order.Status)
147		}
148		return s.orderRepo.Transition(orderID, actorID, "in_transit", "order shipped", s.materialRepo)
149	}
150	
151	// MarkDelivered transitions an order from in_transit → completed.
152	// Only clerks (or admins) may call this.
153	func (s *OrderService) MarkDelivered(orderID, actorID int64) error {
154		order, err := s.orderRepo.GetByID(orderID)
155		if err != nil {
156			return fmt.Errorf("service: MarkDelivered: %w", err)
157		}
158		if order.Status != "in_transit" {
159			return fmt.Errorf("service: MarkDelivered: order is %q, expected in_transit", order.Status)
160		}
161		return s.orderRepo.Transition(orderID, actorID, "completed", "order delivered", s.materialRepo)
162	}
163	
164	// ---------------------------------------------------------------
165	// Returns / Exchanges / Refunds
166	// ---------------------------------------------------------------
167	
168	// RequestReturn submits a return/exchange/refund request for an order.
169	// Rules:
170	//   - The order must belong to the requesting user.
171	//   - Return/exchange: allowed only within 14 days of order completion.
172	//   - Refund: also allowed only within 14 days; requires manager role enforcement
173	//     at the handler layer (admin or instructor).
174	//   - Only one pending request may be open per order at a time.
175	//   - For exchange requests, replacementMaterialID identifies the desired
176	//     replacement item; it is stored and validated at approval time.
177	func (s *OrderService) RequestReturn(orderID, userID int64, reqType, reason string, replacementMaterialID *int64) (*models.ReturnRequest, error) {
178		order, err := s.orderRepo.GetByID(orderID)
179		if err != nil {
180			return nil, fmt.Errorf("service: RequestReturn: %w", err)
181		}
182		if order.UserID != userID {
183			return nil, errors.New("service: RequestReturn: not authorized")
184		}
185		if order.Status != "completed" {
186			return nil, errors.New("service: RequestReturn: returns are only allowed on completed orders")
187		}
188	
189		switch reqType {
190		case "return", "exchange", "refund":
191			// valid types
192		default:
193			return nil, fmt.Errorf("service: RequestReturn: invalid type %q (must be return, exchange, or refund)", reqType)
194		}
195	
196		// Enforce 14-day window.
197		if !repository.WithinReturnWindow(order.UpdatedAt) {
198			return nil, errors.New("service: RequestReturn: the 14-day return window has expired")
199		}
200	
201		// Check for an already-pending request on this order.
202		existing, err := s.orderRepo.GetReturnRequestsByUser(userID)
203		if err != nil {
204			return nil, fmt.Errorf("service: RequestReturn: check existing: %w", err)
205		}
206		for _, rr := range existing {
207			if rr.OrderID == orderID && rr.Status == "pending" {
208				return nil, errors.New("service: RequestReturn: a pending return request already exists for this order")
209			}
210		}
211	
212		rr, err := s.orderRepo.CreateReturnRequest(orderID, userID, reqType, reason, replacementMaterialID)
213		if err != nil {
214			return nil, fmt.Errorf("service: RequestReturn: %w", err)
215		}
216		observability.Orders.Info("return requested", "order_id", orderID, "type", reqType)
217		return rr, nil
218	}
219	
220	// ApproveReturn approves a return request.
221	// Only admins and instructors (managers) may approve.
222	// For exchange requests, the replacement_material_id must be set on the request
223	// and the replacement material must have sufficient available stock.
224	// When the request type is "refund" or "return", a financial_transaction record
225	// is created for traceability.
226	func (s *OrderService) ApproveReturn(requestID, actorID int64, role string) error {
227		if role != "admin" && role != "instructor" {
228			return errors.New("service: ApproveReturn: only managers (admin/instructor) may approve return requests")
229		}
230		rr, err := s.orderRepo.GetReturnRequestByID(requestID)
231		if err != nil {
232			return fmt.Errorf("service: ApproveReturn: %w", err)
233		}
234		if rr.Status != "pending" {
235			return fmt.Errorf("service: ApproveReturn: request is already %q", rr.Status)
236		}
237	
238		// For exchange requests, verify replacement inventory before approving.
239		if rr.Type == "exchange" {
240			if rr.ReplacementMaterialID == nil {
241				return errors.New("service: ApproveReturn: exchange request has no replacement material specified")
242			}
243			replacement, err := s.materialRepo.GetByID(*rr.ReplacementMaterialID)
244			if err != nil {
245				return fmt.Errorf("service: ApproveReturn: load replacement material: %w", err)
246			}
247			if replacement.AvailableQty < 1 {
248				return fmt.Errorf("service: ApproveReturn: replacement material %q has no available stock", replacement.Title)
249			}
250		}
251	
252		// For refund/return types, approval and financial record must both succeed
253		// atomically so the audit trail is never broken.
254		if rr.Type == "refund" || rr.Type == "return" {
255			amount := 0.0
256			if order, oErr := s.orderRepo.GetByID(rr.OrderID); oErr == nil {
257				amount = order.TotalAmount
258			}
259			note := "approved " + rr.Type + " request"
260			if err := s.orderRepo.ApproveReturnWithFinancialRecord(
261				requestID, rr.OrderID, actorID, "refund", amount, note,
262			); err != nil {
263				return fmt.Errorf("service: ApproveReturn: atomic approval+financial record: %w", err)
264			}
265		} else {
266			if err := s.orderRepo.ResolveReturn(requestID, actorID, true); err != nil {
267				return err
268			}
269		}
270	
271		observability.Orders.Info("return approved", "request_id", requestID, "actor_id", actorID, "role", role, "type", rr.Type)
272		return nil
273	}
274	
275	// RejectReturn rejects a return request.
276	// Clerks, admins, and instructors may reject.
277	func (s *OrderService) RejectReturn(requestID, actorID int64) error {
278		rr, err := s.orderRepo.GetReturnRequestByID(requestID)
279		if err != nil {
280			return fmt.Errorf("service: RejectReturn: %w", err)
281		}
282		if rr.Status != "pending" {
283			return fmt.Errorf("service: RejectReturn: request is already %q", rr.Status)
284		}
285		if err := s.orderRepo.ResolveReturn(requestID, actorID, false); err != nil {
286			return err
287		}
288		observability.Orders.Info("return rejected", "request_id", requestID, "actor_id", actorID)
289		return nil
290	}
291	
292	// ---------------------------------------------------------------
293	// Read-through helpers exposed to handlers
294	// ---------------------------------------------------------------
295	
296	// GetOrderByID returns the order and its items.
297	func (s *OrderService) GetOrderByID(orderID int64) (*models.Order, []models.OrderItem, error) {
