303		if err != nil {
304			return nil, nil, fmt.Errorf("service: GetOrderByID: items: %w", err)
305		}
306		return order, items, nil
307	}
308	
309	// GetOrdersForUser returns paginated orders for a user.
310	func (s *OrderService) GetOrdersForUser(userID int64, limit, offset int) ([]models.Order, error) {
311		return s.orderRepo.GetByUserID(userID, limit, offset)
