315	func (s *OrderService) GetAllOrders(status, dateFrom, dateTo string, limit, offset int) ([]models.Order, error) {
316		return s.orderRepo.GetAll(status, dateFrom, dateTo, limit, offset)
317	}
318	
319	// GetOrderEvents returns the event timeline for an order.
320	func (s *OrderService) GetOrderEvents(orderID int64) ([]models.OrderEvent, error) {
321		return s.orderRepo.GetEventsByOrderID(orderID)
322	}
323	
324	// GetReturnRequestsForUser returns all return requests by a user.
325	func (s *OrderService) GetReturnRequestsForUser(userID int64) ([]models.ReturnRequest, error) {
