605	// ApproveReturnWithFinancialRecord atomically approves a return request and
606	// creates the corresponding financial_transactions row in the same database
607	// transaction. If the financial record cannot be written the approval is rolled
608	// back and the error is returned, maintaining strict audit linkage.
609	func (r *OrderRepository) ApproveReturnWithFinancialRecord(
610		requestID, orderID, actorID int64,
611		txType string,
612		amount float64,
613		note string,
614	) error {
615		tx, err := r.db.Begin()
616		if err != nil {
617			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: begin: %w", err)
618		}
619		defer func() {
620			if err != nil {
621				_ = tx.Rollback()
622			}
623		}()
624	
625		const resolveQ = `
626			UPDATE return_requests
627			SET    status      = 'approved',
628			       resolved_at = datetime('now'),
629			       resolved_by = ?
630			WHERE  id = ? AND status = 'pending'`
631	
632		res, err := tx.Exec(resolveQ, actorID, requestID)
633		if err != nil {
634			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: resolve: %w", err)
635		}
636		n, err := res.RowsAffected()
637		if err != nil {
638			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: rows affected: %w", err)
639		}
640		if n == 0 {
641			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: request %d not found or already resolved", requestID)
642		}
643	
644		var notePtr *string
645		if note != "" {
646			notePtr = &note
647		}
648		const ftQ = `
649			INSERT INTO financial_transactions
650			            (order_id, return_request_id, type, amount, status, note, actor_id)
651			VALUES      (?, ?, ?, ?, 'pending', ?, ?)`
652	
653		if _, err = tx.Exec(ftQ, orderID, requestID, txType, amount, notePtr, actorID); err != nil {
654			return fmt.Errorf("repository: ApproveReturnWithFinancialRecord: financial record: %w", err)
655		}
656	
657		return tx.Commit()
658	}
