660	// ---------------------------------------------------------------
661	// Auto-close (scheduler entry point)
662	// ---------------------------------------------------------------
663	
664	// CloseOverdueOrders cancels all orders whose auto_close_at has passed and
665	// whose status is pending_payment or pending_shipment. Returns the count of
666	// orders closed.
667	func (r *OrderRepository) CloseOverdueOrders(materialRepo *MaterialRepository) (int, error) {
668		const selectQ = `
669			SELECT id, status
670			FROM   orders
671			WHERE  status IN ('pending_payment', 'pending_shipment')
672			  AND  auto_close_at IS NOT NULL
673			  AND  auto_close_at < datetime('now')`
674	
675		rows, err := r.db.Query(selectQ)
676		if err != nil {
677			return 0, fmt.Errorf("repository: CloseOverdueOrders: query: %w", err)
678		}
679		type row struct {
680			id     int64
681			status string
682		}
683		var overdue []row
684		for rows.Next() {
685			var rw row
686			if err := rows.Scan(&rw.id, &rw.status); err != nil {
687				rows.Close()
688				return 0, err
689			}
690			overdue = append(overdue, rw)
691		}
692		rows.Close()
693		if err := rows.Err(); err != nil {
694			return 0, err
695		}
696	
697		closed := 0
698		for _, rw := range overdue {
699			note := "auto-closed: payment timeout"
700			if rw.status == "pending_shipment" {
701				note = "auto-closed: shipment timeout"
702			}
703			if err := r.Transition(rw.id, 0, "canceled", note, materialRepo); err != nil {
704				// Log but continue — don't abort the whole batch on a single failure.
705				continue
706			}
707			closed++
708		}
709	
710		return closed, nil
711	}
