761	// MarkOrderItemFulfilled sets the fulfillment_status of the order_item identified
762	// by orderID + materialID to "fulfilled", provided it is currently "pending".
763	// Returns an error when no matching pending row exists (the item may have already
764	// been fulfilled, backordered, or the material/order combination is invalid).
765	func (r *OrderRepository) MarkOrderItemFulfilled(orderID, materialID int64) error {
766		const q = `
767			UPDATE order_items
768			SET    fulfillment_status = 'fulfilled'
769			WHERE  order_id = ? AND material_id = ? AND fulfillment_status = 'pending'`
770		res, err := r.db.Exec(q, orderID, materialID)
771		if err != nil {
772			return err
773		}
774		n, err := res.RowsAffected()
775		if err != nil {
776			return err
777		}
778		if n == 0 {
779			return fmt.Errorf("repository: MarkOrderItemFulfilled: no pending order_item found for order %d material %d", orderID, materialID)
780		}
781		return nil
782	}
