892	// returnWindowDays is the maximum number of days after order completion
893	// within which a return request may be filed.
894	const returnWindowDays = 14
895	
896	// WithinReturnWindow reports whether the given completedAt timestamp is
897	// within the 14-day return window. completedAt must be in RFC3339 format.
898	func WithinReturnWindow(completedAt string) bool {
899		t, err := time.Parse(time.RFC3339, completedAt)
900		if err != nil {
901			// Fallback: attempt SQLite datetime format.
902			t, err = time.Parse("2006-01-02 15:04:05", completedAt)
903			if err != nil {
904				return false
905			}
906		}
907		return time.Since(t) <= time.Duration(returnWindowDays)*24*time.Hour
908	}
