15	// NewTestDB creates an in-memory SQLite DB and runs all migrations.
16	// Uses ":memory:" DSN with foreign keys enabled. Call t.Cleanup to close.
17	func NewTestDB(t *testing.T) *sql.DB {
18		t.Helper()
19		return newTestDB(t, ":memory:?_foreign_keys=on&_journal_mode=WAL")
20	}
21	
22	// NewTestDBNoFK creates an in-memory SQLite DB with foreign key enforcement
23	// disabled.  Use this for tests that exercise code paths that deliberately
24	// pass system-level actor IDs (e.g. 0) that have no corresponding user row.
25	func NewTestDBNoFK(t *testing.T) *sql.DB {
26		t.Helper()
27		return newTestDB(t, ":memory:?_journal_mode=WAL")
28	}
29	
30	func newTestDB(t *testing.T, dsn string) *sql.DB {
31		t.Helper()
32		db, err := sql.Open("sqlite3", dsn)
33		if err != nil {
34			t.Fatalf("open test db: %v", err)
35		}
36		db.SetMaxOpenConns(1)
37		runMigrations(t, db)
38		t.Cleanup(func() { db.Close() })
39		return db
40	}
41	
42	// reStripFTS5 matches the FTS5 virtual table declaration, its associated
43	// triggers, and any single-line comment immediately before them so they can be
44	// removed when FTS5 is not compiled in.
45	var reStripFTS5 = regexp.MustCompile(
46		`(?is)` +
47			// Virtual table declaration
48			`CREATE\s+VIRTUAL\s+TABLE\s+IF\s+NOT\s+EXISTS\s+materials_fts\b.*?;` +
49			`|` +
50			// Single-line comments that describe the FTS block
51			`--[^\n]*fts[^\n]*\n` +
52			`|` +
53			// Trigger blocks (BEGIN … END;)
54			`CREATE\s+TRIGGER\s+IF\s+NOT\s+EXISTS\s+materials_fts_\w+\b.*?END\s*;`,
55	)
56	
57	// runMigrations reads all *.sql files from the migrations directory and
58	// executes them in lexicographic order.  If the SQLite driver does not support
59	// FTS5, the virtual table and its triggers are stripped from the SQL so the
60	// rest of the schema can still be created.
61	func runMigrations(t *testing.T, db *sql.DB) {
62		t.Helper()
63		dir := findMigrationsDir(t)
64	
65		entries, err := os.ReadDir(dir)
66		if err != nil {
67			t.Fatalf("read migrations dir %q: %v", dir, err)
68		}
69	
70		// Collect and sort SQL files lexicographically (matches production order).
71		var files []string
72		for _, e := range entries {
73			if !e.IsDir() && strings.HasSuffix(e.Name(), ".sql") {
74				files = append(files, e.Name())
75			}
76		}
77		sort.Strings(files)
78	
79		// Probe FTS5 support once before running migrations.
80		hasFTS5 := true
81		if _, probeErr := db.Exec("CREATE VIRTUAL TABLE IF NOT EXISTS _fts5_probe USING fts5(x)"); probeErr != nil {
82			hasFTS5 = false
83		} else {
84			db.Exec("DROP TABLE IF EXISTS _fts5_probe") //nolint:errcheck
85		}
86	
87		for _, name := range files {
88			data, err := os.ReadFile(filepath.Join(dir, name))
89			if err != nil {
90				t.Fatalf("read migration %s: %v", name, err)
91			}
92	
93			sql := string(data)
94			if !hasFTS5 {
95				sql = reStripFTS5.ReplaceAllString(sql, "")
96			}
97	
98			if _, err := db.Exec(sql); err != nil {
99				t.Fatalf("run migration %s: %v", name, err)
100			}
101		}
102	}
103	
104	func findMigrationsDir(t *testing.T) string {
105		t.Helper()
106		if p := os.Getenv("MIGRATION_PATH"); p != "" {
107			// Accept either a directory path or a legacy path to 001_schema.sql.
108			if strings.HasSuffix(p, ".sql") {
109				return filepath.Dir(p)
110			}
111			return p
112		}
113		candidates := []string{
114			"../migrations",       // from API_tests/ (repo_root/API_tests)
115			"../../migrations",    // from internal/* packages
116			"../../../migrations", // from internal/sub/packages
117			"migrations",          // from repo root
118		}
119		for _, c := range candidates {
120			if info, err := os.Stat(c); err == nil && info.IsDir() {
121				return c
122			}
123		}
124		t.Fatal("cannot find migrations/ directory - set MIGRATION_PATH env var to the directory path")
125		return ""
126	}
