256				t.Fatalf("CreateComment %d: %v", i, err)
257			}
258		}
259	
260		// CountRecentComments formats `since` as RFC3339 ("2006-01-02T15:04:05Z")
261		// while SQLite's datetime('now') stores "2006-01-02 15:04:05" (space
262		// separator, no Z suffix).  Because space (0x20) < 'T' (0x54), the RFC3339
263		// string always compares GREATER than the stored SQLite string for the same
264		// moment, making "ts >= RFC3339" always FALSE unless the RFC3339 date is
265		// strictly earlier as a string.
266		//
267		// To guarantee "ts >= since" is TRUE for recently inserted rows we use the
268		// zero time (year 0001) which is always earlier than any real timestamp,
269		// regardless of format.
270		since := time.Time{} // epoch zero — always before any real row
271		count, err := repo.CountRecentComments(userID, since)
272		if err != nil {
273			t.Fatalf("CountRecentComments: %v", err)
274		}
275		if count != 3 {
276			t.Errorf("expected 3 recent comments, got %d", count)
277		}
278	
279		// A since value far in the future (year 9999) is always greater than any
280		// stored timestamp and should yield zero results.
281		futureSince := time.Date(9999, 1, 1, 0, 0, 0, 0, time.UTC)
282		count2, err := repo.CountRecentComments(userID, futureSince)
283		if err != nil {
284			t.Fatalf("CountRecentComments future: %v", err)
285		}
286		if count2 != 0 {
287			t.Errorf("expected 0 recent comments with future cutoff, got %d", count2)
288		}
289	}
