1	/**
2	 * map.js — District Materials Portal geospatial map
3	 *
4	 * Initialises a Leaflet map with an offline tile layer, loads GeoJSON from
5	 * /analytics/map/data, handles layer selection, renders a density grid as
6	 * coloured squares, and shows popups on location click.
7	 */
8	
9	(function () {
10	  'use strict';
11	
12	  // ----------------------------------------------------------------
13	  // Initialise Leaflet map with offline tile layer
14	  // ----------------------------------------------------------------
15	  var map = L.map('map', {
16	    center: [39.5, -98.35], // continental US centre — adjust for your district
17	    zoom: 6,
18	    zoomControl: true
19	  });
20	
21	  L.tileLayer('/static/tiles/{z}/{x}/{y}.png', {
22	    attribution: 'District Materials Portal — offline tiles',
23	    maxZoom: 18,
24	    errorTileUrl: '' // silently skip missing tiles in offline mode
25	  }).addTo(map);
26	
27	  // ----------------------------------------------------------------
28	  // Layer groups
29	  // ----------------------------------------------------------------
30	  var locationLayer = L.layerGroup().addTo(map);
31	  var densityLayer  = L.layerGroup().addTo(map);
32	
33	  // ----------------------------------------------------------------
34	  // Marker colours by location type
35	  // ----------------------------------------------------------------
36	  var typeColour = {
37	    school:              '#4a6cf7',
38	    distribution_center: '#f59e0b',
39	    default:             '#6b7280'
40	  };
41	
42	  function markerIcon(locType) {
43	    var colour = typeColour[locType] || typeColour['default'];
44	    var svgIcon = '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="36" viewBox="0 0 24 36">' +
45	      '<path fill="' + colour + '" stroke="#fff" stroke-width="1.5" d="M12 0C5.4 0 0 5.4 0 12c0 9 12 24 12 24s12-15 12-24C24 5.4 18.6 0 12 0z"/>' +
46	      '<circle fill="#fff" cx="12" cy="12" r="5"/>' +
47	      '</svg>';
48	    return L.divIcon({
49	      html: svgIcon,
50	      iconSize: [24, 36],
51	      iconAnchor: [12, 36],
52	      popupAnchor: [0, -36],
53	      className: ''
54	    });
55	  }
56	
57	  // ----------------------------------------------------------------
58	  // Load and render GeoJSON from /analytics/map/data
59	  // ----------------------------------------------------------------
60	  function loadLayerData(layerType) {
61	    var statusEl = document.getElementById('mapStatus');
62	    if (statusEl) statusEl.textContent = 'Loading…';
63	
64	    var url = '/analytics/map/data';
65	    if (layerType && layerType !== '') {
66	      url += '?layer=' + encodeURIComponent(layerType);
67	    }
68	
69	    fetch(url)
70	      .then(function (res) {
71	        if (!res.ok) throw new Error('HTTP ' + res.status);
72	        return res.json();
73	      })
74	      .then(function (data) {
75	        renderLocations(data.geojson, data.locations);
76	        renderDensityGrid(data.aggregates);
77	        if (statusEl) statusEl.textContent = 'Loaded ' + (data.locations ? data.locations.length : 0) + ' location(s).';
78	      })
79	      .catch(function (err) {
80	        if (statusEl) statusEl.textContent = 'Error: ' + err.message;
81	        console.error('map.js: loadLayerData:', err);
82	      });
83	  }
84	
85	  // ----------------------------------------------------------------
86	  // Render location markers from GeoJSON FeatureCollection string
87	  // ----------------------------------------------------------------
88	  function renderLocations(geoJSONStr, rawLocations) {
89	    locationLayer.clearLayers();
90	    if (!geoJSONStr) return;
91	
92	    var fc;
93	    try {
94	      fc = typeof geoJSONStr === 'string' ? JSON.parse(geoJSONStr) : geoJSONStr;
95	    } catch (e) {
96	      console.error('map.js: invalid GeoJSON', e);
97	      return;
98	    }
99	
100	    L.geoJSON(fc, {
101	      pointToLayer: function (feature, latlng) {
102	        var locType = (feature.properties && feature.properties.type) || 'default';
103	        return L.marker(latlng, { icon: markerIcon(locType) });
104	      },
105	      onEachFeature: function (feature, layer) {
106	        if (!feature.properties) return;
107	        var props = feature.properties;
108	        var rows = '';
109	        Object.keys(props).forEach(function (k) {
110	          if (k === 'id') return;
111	          rows += '<tr><th style="text-align:left;padding-right:8px">' + escapeHtml(k) + '</th>' +
112	                  '<td>' + escapeHtml(String(props[k])) + '</td></tr>';
113	        });
114	        var popup = '<strong>' + escapeHtml(props.name || 'Location') + '</strong>' +
115	                    '<table style="margin-top:6px;font-size:0.85rem">' + rows + '</table>';
116	        layer.bindPopup(popup);
117	      }
118	    }).addTo(locationLayer);
119	  }
120	
121	  // ----------------------------------------------------------------
122	  // Render density grid as coloured squares
123	  // ----------------------------------------------------------------
124	  function renderDensityGrid(aggregates) {
125	    densityLayer.clearLayers();
126	    if (!aggregates || aggregates.length === 0) return;
127	
128	    // Find max value for colour scaling
129	    var maxVal = 0;
130	    aggregates.forEach(function (agg) {
131	      var v = agg.value != null ? agg.value : 0;
132	      if (v > maxVal) maxVal = v;
133	    });
134	    if (maxVal === 0) maxVal = 1;
135	
136	    aggregates.forEach(function (agg) {
137	      var cellKey = agg.cell_key || '';
138	      var parts = cellKey.split(',');
139	      if (parts.length < 2) return;
140	
141	      var lat = parseFloat(parts[0]);
142	      var lng = parseFloat(parts[1]);
143	      if (isNaN(lat) || isNaN(lng)) return;
144	
145	      var value = agg.value != null ? agg.value : 0;
146	      var intensity = value / maxVal; // 0..1
147	      var red   = Math.round(239 * intensity);
148	      var green = Math.round(68  * (1 - intensity));
149	      var blue  = Math.round(68  * (1 - intensity));
150	      var colour = 'rgb(' + red + ',' + green + ',' + blue + ')';
151	
152	      // Approximate cell size in degrees (default ~10 km)
153	      var cellDeg = 0.09;
154	
155	      var bounds = [
156	        [lat, lng],
157	        [lat + cellDeg, lng + cellDeg]
158	      ];
159	
160	      var rect = L.rectangle(bounds, {
161	        color: colour,
162	        fillColor: colour,
163	        fillOpacity: 0.4 + 0.4 * intensity,
164	        weight: 0.5
165	      });
166	
167	      rect.bindPopup(
168	        '<strong>Density Cell</strong><br>' +
169	        'Cell: ' + escapeHtml(cellKey) + '<br>' +
170	        'Metric: ' + escapeHtml(agg.metric || '') + '<br>' +
171	        'Value: ' + value
172	      );
173	
174	      rect.addTo(densityLayer);
175	    });
176	  }
177	
178	  // ----------------------------------------------------------------
179	  // Event handlers
180	  // ----------------------------------------------------------------
181	  var layerSelect    = document.getElementById('layerSelect');
182	  var loadLayerBtn   = document.getElementById('loadLayerBtn');
183	  var computeGridBtn = document.getElementById('computeGridBtn');
184	  var gridSizeInput  = document.getElementById('gridSizeInput');
185	  var metricInput    = document.getElementById('metricInput');
186	  var statusEl       = document.getElementById('mapStatus');
187	
188	  if (loadLayerBtn) {
189	    loadLayerBtn.addEventListener('click', function () {
190	      var layer = layerSelect ? layerSelect.value : '';
191	      loadLayerData(layer);
192	    });
193	  }
194	
195	  if (computeGridBtn) {
196	    computeGridBtn.addEventListener('click', function () {
197	      var layer    = layerSelect  ? layerSelect.value  : '';
198	      var gridSize = gridSizeInput ? gridSizeInput.value : '10';
199	      var metric   = metricInput   ? metricInput.value   : 'count';
200	
201	      if (statusEl) statusEl.textContent = 'Computing grid…';
202	
203	      var formData = new FormData();
204	      formData.append('layer',        layer);
205	      formData.append('grid_size_km', gridSize);
206	      formData.append('metric',       metric);
207	
208	      fetch('/analytics/map/compute', { method: 'POST', body: formData })
209	        .then(function (res) { return res.json(); })
210	        .then(function (data) {
211	          if (data.status === 'ok') {
212	            if (statusEl) statusEl.textContent = 'Grid computed. Reloading layer…';
213	            loadLayerData(layer);
214	          } else {
215	            if (statusEl) statusEl.textContent = 'Error: ' + (data.error || 'unknown');
216	          }
217	        })
218	        .catch(function (err) {
219	          if (statusEl) statusEl.textContent = 'Error: ' + err.message;
220	          console.error('map.js: computeGrid:', err);
221	        });
222	    });
223	  }
224	
225	  // Auto-load on page start
226	  loadLayerData('');
227	
228	  // ----------------------------------------------------------------
229	  // Utility
230	  // ----------------------------------------------------------------
231	  function escapeHtml(str) {
232	    return String(str)
233	      .replace(/&/g, '&amp;')
234	      .replace(/</g, '&lt;')
235	      .replace(/>/g, '&gt;')
236	      .replace(/"/g, '&quot;');
237	  }
238	
239	})();
