16	const (
17		maxCommentLength    = 500
18		maxCommentLinks     = 2
19		maxCommentsPerHour  = 5
20		commentRateWindow   = 10 * time.Minute
21		shareTokenDuration  = 7 * 24 * time.Hour
22	)
23	
24	// ---------------------------------------------------------------
25	// WordFilter
26	// ---------------------------------------------------------------
27	
28	// WordFilter checks text against a list of prohibited words using compiled regexps.
29	type WordFilter struct {
30		patterns []*regexp.Regexp
31		words    []string
32	}
33	
34	// NewWordFilter compiles a case-insensitive regexp for each word in the list.
35	func NewWordFilter(words []string) *WordFilter {
36		patterns := make([]*regexp.Regexp, 0, len(words))
37		kept := make([]string, 0, len(words))
38		for _, w := range words {
39			if w == "" {
40				continue
41			}
42			re, err := regexp.Compile(`(?i)\b` + regexp.QuoteMeta(w) + `\b`)
43			if err == nil {
44				patterns = append(patterns, re)
45				kept = append(kept, w)
46			}
47		}
48		return &WordFilter{patterns: patterns, words: kept}
49	}
50	
51	// Contains returns true and the first matching word if text contains any
52	// prohibited word, false and empty string otherwise.
53	func (wf *WordFilter) Contains(text string) (bool, string) {
54		for i, re := range wf.patterns {
55			if re.MatchString(text) {
56				return true, wf.words[i]
57			}
58		}
59		return false, ""
60	}
61	
62	// hrefURLRe matches an href= attribute whose value begins with an https?:// URL.
63	// Consuming the URL here prevents double-counting the bare URL in the next pass.
64	var hrefURLRe = regexp.MustCompile(`(?i)href\s*=\s*["']?https?://[^\s>"']*["']?`)
65	
66	// hrefBareRe matches any remaining href= (relative URLs, anchors) after
67	// hrefURLRe matches have already been stripped.
68	var hrefBareRe = regexp.MustCompile(`(?i)href\s*=`)
69	
70	// plainURLRe matches bare https?:// references not inside an href attribute.
71	var plainURLRe = regexp.MustCompile(`(?i)https?://`)
72	
73	// countLinks counts unique link references in body, deduplicated so that
74	// href=http://... is counted once (not twice as both an href and a bare URL).
75	// This prevents the link-limit from being bypassed via plain URLs.
76	func countLinks(body string) int {
77		n := len(hrefURLRe.FindAllString(body, -1))
78		remaining := hrefURLRe.ReplaceAllLiteralString(body, "")
79		n += len(hrefBareRe.FindAllString(remaining, -1))
80		remaining = hrefBareRe.ReplaceAllLiteralString(remaining, "")
81		n += len(plainURLRe.FindAllString(remaining, -1))
82		return n
83	}
