62	// hrefURLRe matches an href= attribute whose value begins with an https?:// URL.
63	// Consuming the URL here prevents double-counting the bare URL in the next pass.
64	var hrefURLRe = regexp.MustCompile(`(?i)href\s*=\s*["']?https?://[^\s>"']*["']?`)
65	
66	// hrefBareRe matches any remaining href= (relative URLs, anchors) after
67	// hrefURLRe matches have already been stripped.
68	var hrefBareRe = regexp.MustCompile(`(?i)href\s*=`)
69	
70	// plainURLRe matches bare https?:// references not inside an href attribute.
71	var plainURLRe = regexp.MustCompile(`(?i)https?://`)
72	
73	// countLinks counts unique link references in body, deduplicated so that
74	// href=http://... is counted once (not twice as both an href and a bare URL).
75	// This prevents the link-limit from being bypassed via plain URLs.
76	func countLinks(body string) int {
77		n := len(hrefURLRe.FindAllString(body, -1))
78		remaining := hrefURLRe.ReplaceAllLiteralString(body, "")
79		n += len(hrefBareRe.FindAllString(remaining, -1))
80		remaining = hrefBareRe.ReplaceAllLiteralString(remaining, "")
81		n += len(plainURLRe.FindAllString(remaining, -1))
82		return n
83	}
