159	// AddComment validates and posts a new comment.
160	// Rules:
161	//   - body must not exceed 500 characters
162	//   - at most 2 links (href= occurrences) in body
163	//   - body must not contain prohibited words
164	//   - user must not exceed rate limit (5 in the last 10 minutes)
165	func (s *MaterialService) AddComment(materialID, userID int64, body string) (*models.Comment, error) {
166		if len(body) > maxCommentLength {
167			return nil, fmt.Errorf("comment body exceeds maximum length of %d characters", maxCommentLength)
168		}
169	
170		linkCount := countLinks(body)
171		if linkCount > maxCommentLinks {
172			return nil, fmt.Errorf("comment may contain at most %d links", maxCommentLinks)
173		}
174	
175		if found, word := s.wordFilter.Contains(body); found {
176			observability.App.Warn("comment blocked: sensitive word", "user_id", userID, "word", word)
177			return nil, fmt.Errorf("comment contains prohibited content: %q", word)
178		}
179	
180		since := time.Now().UTC().Add(-commentRateWindow)
181		recent, err := s.engagementRepo.CountRecentComments(userID, since)
182		if err != nil {
183			return nil, fmt.Errorf("service: AddComment: rate check: %w", err)
184		}
185		if recent >= maxCommentsPerHour {
186			observability.App.Warn("comment rate limit exceeded", "user_id", userID, "recent_count", recent)
187			return nil, errors.New("comment rate limit exceeded, please try again later")
188		}
189	
190		comment, err := s.engagementRepo.CreateComment(materialID, userID, body, linkCount)
191		if err != nil {
192			return nil, fmt.Errorf("service: AddComment: %w", err)
193		}
194		return comment, nil
195	}
