364	// encKeyFromContext derives the 32-byte AES key from the session user context.
365	// In a real deployment the key would come from the server config; here we
366	// decode the hex string that was loaded into the Fiber app's Locals during
367	// startup (set by main.go as "enc_key").
368	func encKeyFromContext(c *fiber.Ctx) []byte {
369		raw, _ := c.Locals("enc_key").(string)
370		if raw == "" {
371			return nil
372		}
373		key, err := hex.DecodeString(raw)
374		if err != nil || len(key) != 32 {
375			return nil
376		}
377		return key
378	}
